class RedisSessionManager:
    """Manages user sessions stored in Redis."""

    def __init__(self, client, prefix=SESSION_PREFIX, expiry=SESSION_EXPIRY):
        self.client = client
        self.prefix = prefix
        self.expiry = expiry

    def _session_key(self, session_id):
        return f"{self.prefix}{session_id}"

    def create_session(self, user_data):
        """Create a new session and return the session ID."""
        session_id = str(uuid.uuid4())
        key = self._session_key(session_id)
        session_data = {
            "session_id": session_id,
            "created_at": datetime.utcnow().isoformat(),
            "last_accessed": datetime.utcnow().isoformat(),
            **user_data,
        }
        # Store session as a JSON string using SET with expiry
        self.client.set(key, json.dumps(session_data), ex=self.expiry)
        return session_id

    def get_session(self, session_id):
        """Retrieve session data by session ID."""
        key = self._session_key(session_id)
        data = self.client.get(key)
        if data is None:
            return None
        session_data = json.loads(data)
        # Update last accessed time and refresh TTL
        session_data["last_accessed"] = datetime.utcnow().isoformat()
        self.client.set(key, json.dumps(session_data), ex=self.expiry)
        return session_data

    def update_session(self, session_id, update_data):
        """Update specific fields in a session."""
        session_data = self.get_session(session_id)
        if session_data is None:
            return None
        session_data.update(update_data)
        session_data["last_accessed"] = datetime.utcnow().isoformat()
        key = self._session_key(session_id)
        self.client.set(key, json.dumps(session_data), ex=self.expiry)
        return session_data

    def delete_session(self, session_id):
        """Delete a session (logout)."""
        key = self._session_key(session_id)
        return self.client.delete(key) > 0

    def get_active_session_count(self):
        """Count active sessions (for monitoring)."""
        pattern = f"{self.prefix}*"
        count = 0
        for _ in self.client.scan_iter(match=pattern, count=100):
            count += 1
        return count


