def redis_cache(ttl=CACHE_DEFAULT_TTL, prefix=CACHE_PREFIX, key_builder=None):
    """
    Decorator that caches function results in Redis.

    Args:
        ttl: Time-to-live in seconds for cached data.
        prefix: Redis key prefix for cache entries.
        key_builder: Optional callable to build custom cache keys.
                     Receives the function name, args, and kwargs.
    """

    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Build cache key
            if key_builder:
                cache_key_suffix = key_builder(func.__name__, args, kwargs)
            else:
                # Default key: hash of function name + serialized arguments
                key_data = json.dumps(
                    {"func": func.__name__, "args": str(args), "kwargs": str(sorted(kwargs.items()))},
                    sort_keys=True,
                )
                cache_key_suffix = hashlib.sha256(key_data.encode()).hexdigest()

            cache_key = f"{prefix}{func.__name__}:{cache_key_suffix}"

            # Try to get from cache
            try:
                cached = redis_client.get(cache_key)
                if cached is not None:
                    result = json.loads(cached)
                    # Add cache metadata
                    if isinstance(result, dict):
                        result["_cache_hit"] = True
                    return result
            except (redis.ConnectionError, json.JSONDecodeError):
                # If Redis is down or data is corrupt, fall through to function
                pass

            # Cache miss - execute the function
            result = func(*args, **kwargs)

            # Store result in cache
            try:
                redis_client.set(cache_key, json.dumps(result), ex=ttl)
            except (redis.ConnectionError, TypeError):
                # If we can't cache, just return the result
                pass

            if isinstance(result, dict):
                result["_cache_hit"] = False
            return result

        # Add cache invalidation helper
        def invalidate(*args, **kwargs):
            """Manually invalidate cache for specific arguments."""
            if key_builder:
                cache_key_suffix = key_builder(func.__name__, args, kwargs)
            else:
                key_data = json.dumps(
                    {"func": func.__name__, "args": str(args), "kwargs": str(sorted(kwargs.items()))},
                    sort_keys=True,
                )
                cache_key_suffix = hashlib.sha256(key_data.encode()).hexdigest()
            cache_key = f"{prefix}{func.__name__}:{cache_key_suffix}"
            return redis_client.delete(cache_key) > 0

        def invalidate_all():
            """Invalidate all cache entries for this function."""
            pattern = f"{prefix}{func.__name__}:*"
            keys = list(redis_client.scan_iter(match=pattern, count=100))
            if keys:
                return redis_client.delete(*keys)
            return 0

        wrapper.invalidate = invalidate
        wrapper.invalidate_all = invalidate_all
        return wrapper

    return decorator


