@app.before_request
def load_session():
    """Load session data before each request if session token is provided."""
    g.session = None
    g.session_id = None
    session_id = request.headers.get("X-Session-ID") or request.cookies.get("session_id")
    if session_id:
        session_data = session_manager.get_session(session_id)
        if session_data:
            g.session = session_data
            g.session_id = session_id


def require_session(f):
    """Decorator to require a valid session for a route."""

    @functools.wraps(f)
    def decorated(*args, **kwargs):
        if g.session is None:
            return jsonify({"error": "Authentication required", "message": "Please login first"}), 401
        return f(*args, **kwargs)

    return decorated


