@require_session
def update_session():
    """Update session data with custom fields."""
    data = request.get_json()
    if not data:
        return jsonify({"error": "Request body required"}), 400

    # Prevent overwriting critical session fields
    protected_fields = {"session_id", "user_id", "created_at"}
    update_data = {k: v for k, v in data.items() if k not in protected_fields}

    updated = session_manager.update_session(g.session_id, update_data)
    if updated:
        return jsonify({"message": "Session updated", "session": updated})
    return jsonify({"error": "Failed to update session"}), 500


